For your stateless `QrCode` component, use this exact template:

**Location:** `/crates/ars-components/src/specialized/qr_code/mod.rs` or `/crates/ars-components/src/data_display/qr_code.rs`

**Minimal structure:**
```rust
use ars_core::{
    AttrMap, ComponentPart, ConnectApi, Env, HtmlAttr,
};

#[derive(Clone, Debug, Default, PartialEq, ars_core::HasId)]
pub struct Props {
    pub id: String,
    pub value: String,
    pub size: u32,
}

impl Props {
    pub fn new() -> Self { Self::default() }
    pub fn id(mut self, id: impl Into<String>) -> Self { /* ... */ }
}

#[derive(ComponentPart)]
#[scope = "qr-code"]
pub enum Part {
    Root,
}

pub struct Api {
    props: Props,
}

impl Api {
    pub fn new(props: Props) -> Self { Self { props } }
    pub fn root_attrs(&self) -> AttrMap {
        let mut attrs = AttrMap::new();
        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
        attrs.set(scope_attr, scope_val).set(part_attr, part_val);
        attrs
    }
}

impl ConnectApi for Api {
    type Part = Part;
    fn part_attrs(&self, part: Self::Part) -> AttrMap {
        match part {
            Part::Root => self.root_attrs(),
        }
    }
}
