     1	//! `ColorSwatch` connect API.
     2	//!
     3	//! `ColorSwatch` is a stateless, non-interactive display element that renders a
     4	//! color preview with an accessible, perceptual color name for screen readers.
     5	//! No `Machine` is needed — it maps a [`ColorValue`] to attributes directly.
     6	//!
     7	//! The accessible name is derived from [`ColorValue::color_name_parts`] (which
     8	//! returns English keys) assembled by the [`Messages::format_name`] message, so
     9	//! the locale-appropriate ordering and token translations live in the i18n
    10	//! layer rather than in the color math.
    11	
    12	use alloc::{string::String, vec::Vec};
    13	
    14	use ars_core::{
    15	    AriaAttr, AttrMap, ColorNameParts, ColorValue, ComponentMessages, ComponentPart, ConnectApi,
    16	    CssProperty, Env, HtmlAttr, MessageFn,
    17	};
    18	use ars_i18n::Locale;
    19	
    20	/// Formats [`ColorNameParts`] into a single localized accessible name.
    21	type FormatNameFn = dyn Fn(&ColorNameParts, &Locale) -> String + Send + Sync;
    22	/// Returns the localized `aria-roledescription` for the swatch root.
    23	type RoleDescriptionFn = dyn Fn(&Locale) -> String + Send + Sync;
