    36	    /// When `None`, the name is derived from
    37	    /// [`ColorValue::color_name_parts`] + [`Messages::format_name`].
    38	    pub color_name: Option<String>,
    39	
    40	    /// Whether to visually represent the alpha channel (checkerboard pattern).
    41	    pub respect_alpha: bool,
    42	}
    43	
    44	impl Default for Props {
