    let matrix = encode_matrix(&core_props.value, core_props.error_correction);
    let api = qr_code::Api::new(&core_props, matrix, &env, &messages);
    rsx! {
        div { ..api.root_attrs(),
            svg { ..api.pattern_attrs() }
        }
    }
}

