            for ev in events {
                drop(svc.send(ev));
            }

            let api = svc.connect(&|_| {});

            let value = *api.value();

            prop_assert!((0.0..360.0).contains(&value.hue));
            prop_assert!((0.0..=1.0).contains(&value.saturation));
            prop_assert!((0.0..=1.0).contains(&value.lightness));

