                    .map(|(_, value)| value.as_str()),
                Some(pixels.as_str())
            );
        }

        /// The overlay `src` is emitted exactly when `overlay_src` is set.
        #[test]
        #[ignore = "proptest — nightly extended-proptest job"]
        fn qr_overlay_src_emitted_iff_present(props in arb_props()) {
