#[test]
fn large_quiet_zone_does_not_overflow_sizing() {
    // A huge quiet_zone must not panic (debug) or wrap (release) in the
    // usize arithmetic; the f64 sum stays finite and positive.
    let props = Props {
        quiet_zone: usize::MAX,
